<?php require_once 'functions.php'; require_role(['Администратор','Менеджер','Клиент']); layout_header('Кабинет'); $user=$_SESSION['user']; ?>
<h1>Личный кабинет</h1><p>Пользователь: <strong><?=htmlspecialchars($user['login'])?></strong>. Роль: <strong><?=htmlspecialchars($user['role'])?></strong>.</p>
<?php if($user['role']==='Администратор'): ?><h2>Панель администратора</h2><p>Администратор может управлять страницами, пользователями и настройками сайта. В учебной версии показан демонстрационный интерфейс.</p><?php elseif($user['role']==='Менеджер'): ?><h2>Панель менеджера</h2><p>Менеджер обрабатывает заявки клиентов и проверяет сообщения формы обратной связи.</p><?php else: ?><h2>Панель клиента</h2><p>Клиент может просматривать свои заявки и отправлять новые обращения.</p><?php endif; ?>
<h2>Последние обращения</h2><?php $file='storage/messages.json'; $messages=file_exists($file)?json_decode(file_get_contents($file),true):[]; if(!$messages){ echo '<p>Обращений пока нет.</p>'; } else { echo '<table><tr><th>Дата</th><th>Имя</th><th>Email</th><th>Сообщение</th></tr>'; foreach(array_reverse($messages) as $m){ echo '<tr><td>'.htmlspecialchars($m['date']).'</td><td>'.htmlspecialchars($m['name']).'</td><td>'.htmlspecialchars($m['email']).'</td><td>'.htmlspecialchars($m['message']).'</td></tr>'; } echo '</table>'; } ?>
<?php layout_footer(); ?>